var firebaseUrl = "https://robotic-arm-56dc5-default-rtdb.firebaseio.com/"; 
var firebaseSecret = "QsaJnJvDjOIBjHiWd3YHTJ0sE3Pz3OLzKMqWBkiA";

var fireBase = FirebaseApp.getDatabaseByUrl(firebaseUrl,firebaseSecret);

function doGet(e)
{
var action = e.parameter.action;

  if(action == 'getItems')
  {
    return getItems(e);
  }

}
  function getItems(e)
  {
      var myJson = {}; // create a JSON variablbe to store the recceived JSON

      var recceivedData = fireBase.getData(); // store the recceived firebase data to 'recceivedData' variable

      //var myJsonArray = []; // it's used to make the 'JSONArray' type output
      //myJsonArray.push(recceivedData);


    myJson = recceivedData; // insert firebase recceived data to 'myJson' variable; NOTE:use 'myJsonArray' instead 'recceivedData' to make the json array
    var myJsonString=JSON.stringify(myJson); // converting JSON to string
    return ContentService.createTextOutput(myJsonString).setMimeType(ContentService.MimeType.JSON); // returning the JSON Converted String

  }


